SELECT u.user_id, u.user_nm, COALESCE(u.user_info->>'grade_cd', '') AS grade_cd, COALESCE(u.user_info->>'user_status', '') AS user_status, COALESCE(u.user_info->>'corporation_cd', '') AS corporation_cd, COALESCE(u.user_info->>'email_id', '') AS email_id, COALESCE(u.user_info->>'mobile_no', '') AS mobile_no, COALESCE(u.user_info->>'last_login_dtm', '') AS last_login_dtm, COALESCE(u.user_info->>'auth_group', '') AS auth_group, COALESCE(u.user_info->>'second_auth_yn', '') AS second_auth_yn, u.created_at, u.updated_at FROM om_user_m u WHERE u.is_deleted = false ORDER BY
u.user_nm ${sortDirection} u.created_at ${sortDirection} u.user_id ${sortDirection}
LIMIT #{limit} OFFSET #{offset}
